--

CREATE TABLE public.alert_acknowledgments (
    id bigint NOT NULL,
    alert_id bigint NOT NULL,
    acknowledged_by text NOT NULL,
    acknowledged_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    acknowledge_type text NOT NULL,
    message text DEFAULT ''::text NOT NULL,
    false_positive boolean DEFAULT false NOT NULL,
    CONSTRAINT alert_acknowledgments_acknowledge_type_check CHECK ((acknowledge_type = ANY (ARRAY['acknowledge'::text, 'dismiss'::text, 'false_positive'::text])))
);


