    CONSTRAINT chk_retention_days_positive CHECK ((retention_days > 0)),
    CONSTRAINT probe_configs_scope_check CHECK ((scope = ANY (ARRAY['global'::text, 'group'::text, 'cluster'::text, 'server'::text]))),
    CONSTRAINT probe_configs_scope_ids_check CHECK ((((scope = 'global'::text) AND (connection_id IS NULL) AND (group_id IS NULL) AND (cluster_id IS NULL)) OR ((scope = 'group'::text) AND (group_id IS NOT NULL) AND (connection_id IS NULL) AND (cluster_id IS NULL)) OR ((scope = 'cluster'::text) AND (cluster_id IS NOT NULL) AND (connection_id IS NULL) AND (group_id IS NULL)) OR ((scope = 'server'::text) AND (connection_id IS NOT NULL) AND (group_id IS NULL) AND (cluster_id IS NULL))))
);


